use std::fs;
use std::path::PathBuf;

use anyhow::{bail, Context, Result};
use clap::{Parser, ValueEnum};
use rayon::prelude::*;

#[derive(Clone, Debug, ValueEnum)]
enum OutputFormat {
    Gg,
    Json,
    Sarif,
}

#[derive(Clone, Debug, ValueEnum, Default)]
enum ScanMode {
    /// Static analysis mode (default): emit topologies for Betty analysis.
    #[default]
    Analysis,
    /// Orchestration mode: emit topologies with PolyglotBridge* labels + execution manifest.
    Orchestration,
    /// Framework mode (Ditto): detect server frameworks, extract routes, compile to server topology.
    /// Assumes the interface of Express, Flask, Gin, Hono, Sinatra, Spring, etc.
    Framework,
}

#[derive(Debug, Parser)]
#[command(name = "gnosis-polyglot")]
#[command(about = "Universal bug detection via topological verification")]
#[command(
    long_about = "Parses source code in 200+ languages via tree-sitter, extracts control flow \
    into GG topologies, and runs Betty analysis to find bugs no human could."
)]
struct Cli {
    /// File or directory to scan.
    path: PathBuf,

    /// Override language detection (e.g. typescript, rust, python, go, java).
    #[arg(long)]
    language: Option<String>,

    /// Output format.
    #[arg(long, value_enum, default_value_t = OutputFormat::Json)]
    format: OutputFormat,

    /// Only analyze a specific function by name.
    #[arg(long)]
    function: Option<String>,

    /// Print the .gg source for each function (useful for debugging).
    #[arg(long, default_value_t = false)]
    print_gg: bool,

    /// Scan mode: analysis (default) or orchestration (for execution).
    #[arg(long, value_enum, default_value_t = ScanMode::Analysis)]
    mode: ScanMode,

    /// Parse a .gg topology file (instead of scanning source code).
    /// Outputs the parsed AST as JSON with node/edge counts and beta-1.
    #[arg(long, default_value_t = false)]
    parse_gg: bool,

    /// When using --parse-gg, only print the beta-1 number.
    #[arg(long, default_value_t = false)]
    beta1: bool,

    /// When using --parse-gg, benchmark N iterations and print timing.
    #[arg(long)]
    bench: Option<usize>,

    /// Run Becky (full Rust compiler): parse + validate + beta-1 + diagnostics.
    #[arg(long, default_value_t = false)]
    compile: bool,

    /// (Orchestration mode only) Follow relative imports from the entry file
    /// and emit a unified topology list covering all transitively imported
    /// sibling modules. Supports TypeScript, Python, and Lean entry files; the
    /// BFS stays inside the entry file's language. Off by default to preserve
    /// existing single-file behavior.
    #[arg(long, default_value_t = false)]
    resolve_imports: bool,

    /// Cap on transitive import depth when `--resolve-imports` is set.
    #[arg(long, default_value_t = gnosis_polyglot::multi_file::DEFAULT_MAX_IMPORT_DEPTH)]
    max_import_depth: usize,

    /// Emit protocol69 app teleport receipts: source app -> .gg -> cache key.
    #[arg(long, default_value_t = false)]
    protocol69_teleport: bool,

    /// Optional room identifier folded into the protocol69 RF cache key.
    #[arg(long)]
    room_id: Option<String>,

    /// Optional RF carrier frequency in Hz folded into the protocol69 cache key.
    #[arg(long)]
    carrier_hz: Option<u64>,

    /// Optional attenuation setting in dB folded into the protocol69 cache key.
    #[arg(long)]
    attenuation_db: Option<i64>,

    /// Number of attached antennas in the in-room protocol69 RF session.
    #[arg(long, default_value_t = 2)]
    antenna_count: usize,
}

fn main() {
    if let Err(error) = run() {
        eprintln!("gnosis-polyglot: {error:#}");
        std::process::exit(1);
    }
}

fn run() -> Result<()> {
    let cli = Cli::parse();

    if cli.compile {
        return compile_gg_file(&cli);
    }

    if cli.parse_gg {
        return parse_gg_file(&cli);
    }

    if cli.protocol69_teleport {
        return scan_file_protocol69_teleport(&cli, &cli.path);
    }

    if cli.path.is_dir() {
        scan_directory(&cli)
    } else {
        scan_file(&cli, &cli.path)
    }
}

fn compile_gg_file(cli: &Cli) -> Result<()> {
    let source = read_gg_family_source(&cli.path)?;

    if let Some(iterations) = cli.bench {
        use std::time::Instant;
        for _ in 0..10 {
            let _ = gnosis_polyglot::becky::compile(&source);
        }
        let start = Instant::now();
        for _ in 0..iterations {
            let _ = gnosis_polyglot::becky::compile(&source);
        }
        let elapsed = start.elapsed();
        let per_iter_ns = elapsed.as_nanos() as f64 / iterations as f64;
        let result = gnosis_polyglot::becky::compile(&source);
        println!(
            "{}ns/iter ({:.3}us) | {} iterations | {} nodes {} edges | beta1={} | {} diagnostics | void_dims={} landauer={:.3} deficit={}",
            per_iter_ns as u64,
            per_iter_ns / 1000.0,
            iterations,
            result.program.nodes.len(),
            result.program.edges.len(),
            result.beta1,
            result.diagnostics.len(),
            result.void_dimensions,
            result.landauer_heat,
            result.total_deficit,
        );
        return Ok(());
    }

    let result = gnosis_polyglot::becky::compile(&source);
    println!("{}", serde_json::to_string_pretty(&result)?);
    Ok(())
}

fn parse_gg_file(cli: &Cli) -> Result<()> {
    let source = read_gg_family_source(&cli.path)?;

    if let Some(iterations) = cli.bench {
        use std::time::Instant;
        // Warmup
        for _ in 0..10 {
            let _ = gnosis_polyglot::gg_parser::parse_gg(&source);
        }
        let start = Instant::now();
        for _ in 0..iterations {
            let _ = gnosis_polyglot::gg_parser::parse_gg(&source);
        }
        let elapsed = start.elapsed();
        let per_iter_ns = elapsed.as_nanos() as f64 / iterations as f64;
        let program = gnosis_polyglot::gg_parser::parse_gg(&source);
        println!(
            "{}ns/iter ({:.3}us) | {} iterations | {} nodes {} edges | beta1={}",
            per_iter_ns as u64,
            per_iter_ns / 1000.0,
            iterations,
            program.nodes.len(),
            program.edges.len(),
            gnosis_polyglot::gg_parser::compute_beta1(&program)
        );
        return Ok(());
    }

    let program = gnosis_polyglot::gg_parser::parse_gg(&source);
    let beta1 = gnosis_polyglot::gg_parser::compute_beta1(&program);

    if cli.beta1 {
        println!("{beta1}");
        return Ok(());
    }

    #[derive(serde::Serialize)]
    struct ParseResult {
        nodes: usize,
        edges: usize,
        beta1: i64,
        program: gnosis_polyglot::gg_parser::GgProgram,
    }

    let result = ParseResult {
        nodes: program.nodes.len(),
        edges: program.edges.len(),
        beta1,
        program,
    };

    println!("{}", serde_json::to_string_pretty(&result)?);
    Ok(())
}

fn scan_directory(cli: &Cli) -> Result<()> {
    let extractors = gnosis_polyglot::extractors::all_extractors();
    let mut supported_extensions: Vec<&str> = extractors
        .iter()
        .flat_map(|e| e.file_extensions().to_vec())
        .collect();
    supported_extensions.push(".gnarly");

    let mut files = Vec::new();
    collect_files(&cli.path, &supported_extensions, &mut files)?;

    if files.is_empty() {
        eprintln!("no supported source files found in {}", cli.path.display());
        return Ok(());
    }

    eprintln!("scanning {} files...", files.len());

    let all_results: Vec<_> = files
        .par_iter()
        .filter_map(|file| match scan_file_inner(file) {
            Ok(result) => Some(result),
            Err(e) => {
                eprintln!("  error in {}: {e}", file.display());
                None
            }
        })
        .collect();

    // Print combined results.
    match cli.format {
        OutputFormat::Json => {
            println!("{}", serde_json::to_string_pretty(&all_results)?);
        }
        OutputFormat::Gg => {
            for result in &all_results {
                for topo in &result.topologies {
                    println!("{}", topo.gg_source);
                }
            }
        }
        OutputFormat::Sarif => {
            let mut all_diags = Vec::new();
            let mut sources = std::collections::HashMap::new();
            for result in &all_results {
                for topo in &result.topologies {
                    let diags = gnosis_polyglot::diagnostics::analyze_topology(&topo.topology);
                    // Collect source files referenced by diagnostics.
                    for diag in &diags {
                        if let Some(ref loc) = diag.location {
                            if !sources.contains_key(&loc.file) {
                                if let Ok(src) = fs::read_to_string(&loc.file) {
                                    sources.insert(loc.file.clone(), src);
                                }
                            }
                        }
                    }
                    all_diags.extend(diags);
                }
            }
            // Filter out suppressed diagnostics (polyglot:ignore comments).
            let all_diags = gnosis_polyglot::diagnostics::filter_suppressed(all_diags, &sources);
            let file = all_results
                .first()
                .map(|r| r.file_path.as_str())
                .unwrap_or("unknown");
            let lang = all_results
                .first()
                .map(|r| r.language.as_str())
                .unwrap_or("unknown");
            let sarif = gnosis_polyglot::diagnostics::diagnostics_to_sarif(file, lang, &all_diags);
            println!("{}", serde_json::to_string_pretty(&sarif)?);
        }
    }

    // Summary.
    let total_functions: usize = all_results.iter().map(|r| r.topologies.len()).sum();
    let total_errors: usize = all_results.iter().map(|r| r.errors.len()).sum();
    eprintln!(
        "scanned {} files, {} functions, {} errors",
        all_results.len(),
        total_functions,
        total_errors
    );

    Ok(())
}

fn read_gg_family_source(path: &PathBuf) -> Result<String> {
    let source = fs::read_to_string(path).with_context(|| format!("reading {}", path.display()))?;
    let path_str = path.to_string_lossy();
    if gnosis_polyglot::gnarly::is_gnarly_path(&path_str) {
        Ok(gnosis_polyglot::gnarly::normalize_gnarly_to_gg(
            &source, &path_str,
        ))
    } else {
        Ok(source)
    }
}

fn scan_file(cli: &Cli, file_path: &PathBuf) -> Result<()> {
    // Orchestration mode: produce execution-ready output.
    if matches!(cli.mode, ScanMode::Orchestration) {
        return scan_file_orchestration(cli, file_path);
    }

    // Framework mode (Ditto): detect framework, extract routes, compile to server GG.
    if matches!(cli.mode, ScanMode::Framework) {
        return scan_file_framework(cli, file_path);
    }

    let result = scan_file_inner(file_path)?;

    match cli.format {
        OutputFormat::Json => {
            println!("{}", serde_json::to_string_pretty(&result)?);
        }
        OutputFormat::Gg => {
            for topo in &result.topologies {
                if let Some(ref filter_fn) = cli.function {
                    if &topo.function_name != filter_fn {
                        continue;
                    }
                }
                println!("{}", topo.gg_source);
            }
        }
        OutputFormat::Sarif => {
            let mut all_diags = Vec::new();
            for topo in &result.topologies {
                let diags = gnosis_polyglot::diagnostics::analyze_topology(&topo.topology);
                all_diags.extend(diags);
            }
            // Filter suppressed diagnostics.
            let mut sources = std::collections::HashMap::new();
            if let Ok(src) = fs::read_to_string(file_path) {
                sources.insert(result.file_path.clone(), src);
            }
            let all_diags = gnosis_polyglot::diagnostics::filter_suppressed(all_diags, &sources);
            let sarif = gnosis_polyglot::diagnostics::diagnostics_to_sarif(
                &result.file_path,
                &result.language,
                &all_diags,
            );
            println!("{}", serde_json::to_string_pretty(&sarif)?);
        }
    }

    if cli.print_gg {
        for topo in &result.topologies {
            eprintln!("--- {} ---", topo.function_name);
            eprintln!("{}", topo.gg_source);
        }
    }

    if !result.errors.is_empty() {
        for err in &result.errors {
            eprintln!("error: {}", err.message);
        }
        std::process::exit(1);
    }

    Ok(())
}

fn scan_file_inner(
    file_path: &PathBuf,
) -> Result<gnosis_polyglot::serialization::PolyglotScanResult> {
    let source = fs::read_to_string(file_path)
        .with_context(|| format!("failed to read {}", file_path.display()))?;

    // Skip very large files (>10K lines) -- likely generated/bundled code.
    if source.lines().count() > 10_000 {
        return Ok(gnosis_polyglot::serialization::PolyglotScanResult {
            file_path: file_path.to_string_lossy().to_string(),
            language: "skipped".to_string(),
            structured_declarations: Vec::new(),
            proof_declarations: Vec::new(),
            topologies: Vec::new(),
            errors: Vec::new(),
        });
    }

    let path_str = file_path.to_string_lossy();
    gnosis_polyglot::parse_and_extract(&source, &path_str)
}

fn scan_file_orchestration(cli: &Cli, file_path: &PathBuf) -> Result<()> {
    // --resolve-imports runs the multi-file BFS and folds the flat topology
    // list back into a PolyglotOrchestrationResult before serializing.
    let result = if cli.resolve_imports {
        let multi =
            gnosis_polyglot::multi_file::resolve_imports_recursive(file_path, cli.max_import_depth)
                .with_context(|| {
                    format!("multi-file resolve failed for {}", file_path.display())
                })?;
        gnosis_polyglot::multi_file::to_orchestration_result(multi)
    } else {
        let source = fs::read_to_string(file_path)
            .with_context(|| format!("failed to read {}", file_path.display()))?;
        let path_str = file_path.to_string_lossy();
        gnosis_polyglot::parse_and_extract_orchestration(&source, &path_str)?
    };

    match cli.format {
        OutputFormat::Json => {
            println!("{}", serde_json::to_string_pretty(&result)?);
        }
        OutputFormat::Gg => {
            for topo in &result.scan_result.topologies {
                if let Some(ref filter_fn) = cli.function {
                    if &topo.function_name != filter_fn {
                        continue;
                    }
                }
                println!("{}", topo.gg_source);
            }
        }
        OutputFormat::Sarif => {
            // Orchestration mode doesn't support SARIF; fall back to JSON.
            println!("{}", serde_json::to_string_pretty(&result)?);
        }
    }

    if cli.print_gg {
        for topo in &result.scan_result.topologies {
            eprintln!("--- {} ---", topo.function_name);
            eprintln!("{}", topo.gg_source);
        }
    }

    if !result.scan_result.errors.is_empty() {
        for err in &result.scan_result.errors {
            eprintln!("error: {}", err.message);
        }
        std::process::exit(1);
    }

    Ok(())
}

fn scan_file_protocol69_teleport(cli: &Cli, file_path: &PathBuf) -> Result<()> {
    if file_path.is_dir() {
        bail!("--protocol69-teleport expects a file path, not a directory");
    }

    let result = if cli.resolve_imports {
        let multi =
            gnosis_polyglot::multi_file::resolve_imports_recursive(file_path, cli.max_import_depth)
                .with_context(|| {
                    format!("multi-file resolve failed for {}", file_path.display())
                })?;
        gnosis_polyglot::multi_file::to_orchestration_result(multi)
    } else {
        let source = fs::read_to_string(file_path)
            .with_context(|| format!("failed to read {}", file_path.display()))?;
        let path_str = file_path.to_string_lossy();
        gnosis_polyglot::parse_and_extract_orchestration(&source, &path_str)?
    };

    let mut report =
        gnosis_polyglot::protocol69_app_teleport::build_protocol69_polyglot_app_teleport_report(
            &result,
            protocol69_session_from_cli(cli)?,
        );

    if let Some(ref filter_fn) = cli.function {
        report
            .receipts
            .retain(|receipt| &receipt.key_material.function_name == filter_fn);
    }

    println!("{}", serde_json::to_string_pretty(&report)?);

    if !result.scan_result.errors.is_empty() {
        for err in &result.scan_result.errors {
            eprintln!("error: {}", err.message);
        }
        std::process::exit(1);
    }

    Ok(())
}

fn protocol69_session_from_cli(
    cli: &Cli,
) -> Result<gnosis_polyglot::protocol69_app_teleport::Protocol69InRoomRfSession> {
    if cli.antenna_count == 0 {
        bail!("--antenna-count must be greater than zero");
    }

    Ok(
        gnosis_polyglot::protocol69_app_teleport::Protocol69InRoomRfSession {
            antenna_count: cli.antenna_count,
            room_id: cli.room_id.clone(),
            carrier_hz: cli.carrier_hz,
            attenuation_db: cli.attenuation_db,
            ..gnosis_polyglot::protocol69_app_teleport::protocol69_default_in_room_rf_session()
        },
    )
}

fn scan_file_framework(cli: &Cli, file_path: &PathBuf) -> Result<()> {
    let source = fs::read_to_string(file_path)
        .with_context(|| format!("failed to read {}", file_path.display()))?;

    let path_str = file_path.to_string_lossy();
    let result = gnosis_polyglot::parse_and_extract_framework(&source, &path_str)?;

    match cli.format {
        OutputFormat::Json => {
            println!("{}", serde_json::to_string_pretty(&result)?);
        }
        OutputFormat::Gg => {
            if let Some(ref ft) = result.topology {
                // Compile framework topology to GG server topology.
                let gg = gnosis_polyglot::framework_compiler::compile_framework_to_gg(ft);
                println!("{}", gg);
            } else {
                // No framework detected -- fall back to standard GG output.
                for topo in &result.scan_result.topologies {
                    if let Some(ref filter_fn) = cli.function {
                        if &topo.function_name != filter_fn {
                            continue;
                        }
                    }
                    println!("{}", topo.gg_source);
                }
            }
        }
        OutputFormat::Sarif => {
            // Framework mode doesn't support SARIF; fall back to JSON.
            println!("{}", serde_json::to_string_pretty(&result)?);
        }
    }

    if let Some(ref ft) = result.topology {
        eprintln!(
            "ditto: detected {} ({}) -- {} routes, {} middleware",
            ft.framework,
            ft.language,
            ft.routes.len(),
            ft.middleware.len()
        );
        if let Some(port) = ft.listen_port {
            eprintln!("ditto: listen port {}", port);
        }
    } else {
        eprintln!("ditto: no framework detected in {}", file_path.display());
    }

    if !result.scan_result.errors.is_empty() {
        for err in &result.scan_result.errors {
            eprintln!("error: {}", err.message);
        }
        std::process::exit(1);
    }

    Ok(())
}

/// Detect bundled/generated JS chunks (e.g., `chunk-abc123.js`, `1234.abcdef.js`).
fn is_bundled_chunk(name: &str) -> bool {
    if !(name.ends_with(".js") || name.ends_with(".mjs")) {
        return false;
    }
    // Pattern: starts with "chunk-" (Vite/Rollup)
    if name.starts_with("chunk-") {
        return true;
    }
    // Pattern: <number>.<hex>.iframe.bundle.js (Storybook)
    if name.contains(".iframe.") {
        return true;
    }
    // Pattern: <hash>.js where hash is hex (webpack numeric chunks)
    let stem = name.rsplit('.').nth(1).unwrap_or("");
    if stem.len() >= 6 && stem.chars().all(|c| c.is_ascii_hexdigit()) {
        return true;
    }
    // Pattern: digit-prefixed files like 1234.abcdef.js (webpack chunks)
    if let Some(first) = name.chars().next() {
        if first.is_ascii_digit() && name.contains('.') {
            let parts: Vec<&str> = name.split('.').collect();
            if parts.len() >= 3 {
                return true;
            }
        }
    }
    false
}

fn collect_files(dir: &PathBuf, extensions: &[&str], files: &mut Vec<PathBuf>) -> Result<()> {
    let entries =
        fs::read_dir(dir).with_context(|| format!("failed to read directory {}", dir.display()))?;

    for entry in entries {
        let entry = entry?;
        let path = entry.path();

        // Skip hidden dirs, vendor, and build artifacts.
        if let Some(name) = path.file_name().and_then(|n| n.to_str()) {
            if name.starts_with('.')
                || name == "node_modules"
                || name == "target"
                || name == "dist"
                || name == "build"
                || name == "vendor"
                || name == "__pycache__"
                || name == ".git"
                || name == "coverage"
                || name == "out"
                || name == "storybook-static"
                || name == ".next"
                || name == ".turbo"
                || name == "fixtures"
            {
                continue;
            }
        }

        // Skip minified, bundled, and generated files.
        if path.is_file() {
            if let Some(fname) = path.file_name().and_then(|n| n.to_str()) {
                if fname.contains(".min.")
                    || fname.contains(".bundle.")
                    || fname.ends_with(".min.js")
                    || fname.ends_with(".min.mjs")
                    || is_bundled_chunk(fname)
                {
                    continue;
                }
            }
        }

        if path.is_dir() {
            collect_files(&path, extensions, files)?;
        } else if let Some(ext) = path.extension().and_then(|e| e.to_str()) {
            let dot_ext = format!(".{ext}");
            if extensions.contains(&dot_ext.as_str()) {
                files.push(path);
            }
        }
    }

    Ok(())
}
